package com.vidaysalud.veterinaria.medicamentoservicio.controller;import com.vidaysalud.veterinaria.medicamentoservicio.dto.*;import com.vidaysalud.veterinaria.medicamentoservicio.service.MedicamentoService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/medicamentos") @RequiredArgsConstructor public class MedicamentoController{private final MedicamentoService s;@GetMapping public ResponseEntity<ApiResponse<List<MedicamentoResponseDTO>>> l(){return ok("Medicamentos obtenidos",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<MedicamentoResponseDTO>> b(@PathVariable Integer id){return ok("Medicamento encontrado",s.buscar(id));}@PostMapping public ResponseEntity<ApiResponse<MedicamentoResponseDTO>> c(@Valid @RequestBody MedicamentoRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Medicamento creado",s.crear(d)));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<MedicamentoResponseDTO>>u(@PathVariable Integer id,@Valid @RequestBody MedicamentoRequestDTO d){return ok("Medicamento actualizado",s.actualizar(id,d));}@PatchMapping("/{id}/stock")public ResponseEntity<ApiResponse<MedicamentoResponseDTO>>st(@PathVariable Integer id,@Valid @RequestBody StockRequestDTO d){return ok("Stock actualizado",s.actualizarStock(id,d.getStock()));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Medicamento eliminado",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}